{
  "summary": "This paper proposes embedding-based out-of-distribution (OOD) detection methods for conditional language models (CLMs) using Gaussian modeling of input and output embeddings and introduces a Relative Mahalanobis Distance (RMD) score. It combines these OOD scores with perplexity to enable selective generation, abstaining from low-quality outputs under distribution shift, and evaluates the approach on summarization and translation tasks with human and automatic quality metrics.",
  "strengths": [
    {
      "point": "Novel embedding-based OOD detection tailored for CLMs",
      "evidence": "The method leverages final-layer encoder and decoder embeddings to fit Gaussian distributions and compute Mahalanobis distances, providing lightweight OOD scores without requiring separate detection models."
    },
    {
      "point": "Effective combination of OOD scores with perplexity for selective generation",
      "evidence": "Combining OOD detection scores with perplexity improves quality prediction by up to 12% absolute on summarization and 8% on translation, outperforming single metrics and external quality estimators like COMET."
    },
    {
      "point": "Comprehensive evaluation framework including human ratings",
      "evidence": "The paper evaluates OOD detection using AUROC and selective generation with quality vs abstention curves, supported by human quality ratings for summarization and BLEURT for translation."
    },
    {
      "point": "Insightful analysis of OOD detection limitations of perplexity",
      "evidence": "Perplexity distributions overlap heavily between in-domain and OOD data, confirming its unsuitability for OOD detection in CLMs."
    },
    {
      "point": "Potential applicability beyond tested tasks",
      "evidence": "Authors claim the method is task-agnostic and potentially applicable to other sequence generation tasks and model architectures, including decoder-only models."
    }
  ],
  "weaknesses": [
    {
      "point": "Insufficient comparison to recent state-of-the-art OOD detection methods",
      "evidence": "The evaluation omits comparisons to uncertainty estimation techniques (e.g., Monte Carlo dropout, deep ensembles) and density estimation methods (e.g., normalizing flows), leaving unclear if RMD advances the state-of-the-art."
    },
    {
      "point": "Unjustified Gaussian assumption and embedding averaging",
      "evidence": "No theoretical or empirical justification is provided for modeling embeddings as Gaussians or for averaging token embeddings to form sequence embeddings; alternative modeling and pooling strategies are not explored."
    },
    {
      "point": "Limited diversity and realism of OOD datasets",
      "evidence": "OOD datasets are mostly near-domain or domain-shifted corpora, lacking truly out-of-distribution examples such as adversarial or unrelated domain inputs; some datasets have high n-gram overlap with training data."
    },
    {
      "point": "Overreliance on AUROC without complementary OOD metrics",
      "evidence": "The paper reports primarily AUROC, omitting metrics like AUPRC, FPR@95TPR, or calibration errors that are important for practical deployment."
    },
    {
      "point": "Insufficient methodological and reproducibility details",
      "evidence": "Key implementation details such as embedding dimensionality, Transformer layers used, Gaussian covariance structure, and classifier training procedures are missing."
    },
    {
      "point": "Ambiguous definition and rationale for Relative Mahalanobis Distance",
      "evidence": "No formal mathematical definition or theoretical motivation is provided for using the difference of Mahalanobis distances rather than other combinations."
    },
    {
      "point": "No quantitative analysis of computational overhead",
      "evidence": "The paper claims the method is lightweight but does not provide runtime benchmarks or complexity analyses compared to baselines."
    },
    {
      "point": "Unsupported claims of applicability to decoder-only models",
      "evidence": "No experiments or analyses are presented to validate the method on decoder-only architectures like GPT-3."
    },
    {
      "point": "Lack of ablation studies on combining OOD scores with perplexity",
      "evidence": "The paper does not ablate the individual contributions or explore alternative fusion strategies beyond linear regression or percentile summation."
    },
    {
      "point": "Insufficient explanation and evaluation of sentence-level OOD attribution",
      "evidence": "The method for attributing OOD scores to individual sentences is mentioned but lacks algorithmic detail, examples, or validation."
    },
    {
      "point": "Limited evaluation scope: no multilingual or cross-lingual analysis",
      "evidence": "Experiments focus only on English summarization and English-French translation, limiting understanding of generalizability."
    },
    {
      "point": "No analysis of model calibration or confidence reliability",
      "evidence": "Calibration metrics such as expected calibration error are not reported, which are important for safe abstention decisions."
    },
    {
      "point": "No discussion of failure modes or adversarial vulnerabilities",
      "evidence": "Potential failure scenarios where OOD detection or selective generation might fail are not analyzed."
    },
    {
      "point": "Insufficient details on human evaluation protocol",
      "evidence": "Annotation procedures, rating scales, inter-annotator agreement, and quality control for human ratings are not described."
    },
    {
      "point": "No assessment of downstream task or user-centric metrics beyond quality scores",
      "evidence": "Metrics such as informativeness, usefulness, or user satisfaction are not evaluated."
    },
    {
      "point": "Abstention threshold selection and impact not addressed",
      "evidence": "The method requires thresholding combined scores to abstain but does not discuss threshold selection or downstream effects."
    },
    {
      "point": "Lack of empirical analysis of error propagation mitigation",
      "evidence": "Although error propagation in auto-regressive generation is a motivation, no empirical analysis shows how the method mitigates it."
    }
  ],
  "questions": [
    {
      "question": "How does the proposed RMD compare empirically to recent uncertainty estimation and density-based OOD detection methods on CLMs?",
      "motivation": "Understanding comparative performance is critical to establish novelty and practical advantage."
    },
    {
      "question": "How sensitive is the method to the Gaussian assumption and the choice of embedding pooling strategy?",
      "motivation": "Robustness and generality depend on these modeling choices; alternatives might improve detection."
    },
    {
      "question": "What are the computational costs and latency implications of embedding extraction and OOD scoring in real-time or large-scale settings?",
      "motivation": "Practical deployment requires understanding efficiency and scalability."
    },
    {
      "question": "How can abstention thresholds be selected systematically, and what is their impact on user experience and downstream tasks?",
      "motivation": "Thresholding affects usability and effectiveness of selective generation."
    },
    {
      "question": "Can the method be adapted and validated on decoder-only models, and what embedding extraction strategies would be effective there?",
      "motivation": "Extending applicability to popular models like GPT-3 is important for broader impact."
    },
    {
      "question": "How well calibrated are the OOD scores and combined quality predictions, and can calibration be improved?",
      "motivation": "Calibration affects reliability and safety of abstention decisions."
    }
  ],
  "scores": {
    "correctness": 3,
    "novelty": 3,
    "recommendation": "borderline",
    "confidence": 3
  }
}
